"""
MKT Original Language Commentary — Psalms chapters 120–133 (Songs of Ascents)
Run: python3 scripts/zc-original-psalms-120-133.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json

Key decisions in this range:
- Ps 120–134: the Songs of Ascents (šîr hamaʿălôt) — 15 psalms for pilgrims ascending to
  Jerusalem; maʿălôt can mean "steps/stairs" or "ascents/goings up"
- Ps 120:5: Meshech (Anatolia) + Kedar (Arabia) = the ends of the earth, representing exile
- Ps 121: šōmēr (keeper) appears 6x in 8 verses; v1 question is genuine not affirmative
- Ps 122: šaʾălû šĕlôm yĕrûšālāim (pray for Jerusalem's peace) — triple šālôm wordplay
- Ps 126: šîbat ṣiyyôn = restoration of Zion; hāyînû kĕḥōlĕmîm (we were like dreamers)
- Ps 127: attributed to Solomon (lĕšĕlōmōh); bayit (house/dynasty) double meaning;
  šāwĕʾ (vain/empty) = Ecclesiastes' hebel register
- Ps 130: sĕlîḥāh (forgiveness/pardon) — rare word (only 3x in OT); v5-6 waiting imagery
- Ps 132: longest of the Ascents; qeren (horn) + ṣāmaḥ (sprout) in v17 = Messianic Shoot;
  ʾāraktî nēr (I have prepared a lamp) for the anointed; echoed in Luke 1:69, 2:32
- Ps 133: šemen haṭṭôb (precious oil) on Aaron's head = unity framed as anointing;
  tal-ḥermôn (dew of Hermon) as proverbial abundance descending on Zion
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 120-133 — the Songs of Ascents, the pilgrim psalms
#   for the journey to Jerusalem; 98 verses across 14 chapters.
# CHANGE? If commentary/mkt-original/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json'));
#   [print(ch, len(d[ch])) for ch in [str(i) for i in range(120,134)]]"

PSALMS = {
  "120": {
    "1": '<p><strong>šîr hamaʿălôt</strong> — "a song of the ascents" — the superscription that opens Ps 120 and heads each of the 15 psalms through Ps 134. <em>maʿălôt</em> (ascents, goings up, steps) from <em>ʿālāh</em> (to go up, ascend) — traditionally understood as songs sung by pilgrims ascending to Jerusalem for the three annual festivals (Deut 16:16), or as liturgical songs chanted on the fifteen steps of the temple. <em>baṣṣārāh lî qārāʾtî ʾel-yhwh wayyaʿănēnî</em> — "in my distress I cried to the LORD, and he answered me" — the psalm opens with a completed rescue, framing the distress as already heard. This retrospective structure is characteristic of thanksgiving psalms.</p>',
    "2": '<p><strong>yhwh haṣṣîlāh napšî miśśĕpat-šāqer millāšôn rĕmiyyāh</strong> — "O LORD, rescue my life from lying lips, from a deceitful tongue" — two paired nouns: <em>śĕpat-šāqer</em> (lying/falsehood lip) and <em>lāšôn rĕmiyyāh</em> (tongue of deceit/treachery). <em>rĕmiyyāh</em> (deceit, slackness, treachery, from <em>rāmāh</em>, to deceive, throw) — the word carries active betrayal, not merely casual dishonesty. The pilgrim\'s first distress is not war or famine but the social violence of false speech in a hostile environment.</p>',
    "3": '<p><strong>mah-yittēn lĕkā ûmah-yōsîp lāk lāšôn rĕmiyyāh</strong> — "what will be given to you, and what more will be done for you, O deceitful tongue?" — a taunt-address to the lying tongue itself. The rhetorical questions set up v4\'s answer. The verse form (what will be given? what will be added?) echoes the curse-formula of ancient Near Eastern treaty violations: the offending party is asked what they deserve before the punishment is declared.</p>',
    "4": '<p><strong>ḥiṣṣê gibbôr šĕnûnîm ʿim gaḥălê rĕtāmîm</strong> — "sharp arrows of a mighty man, with burning coals of broom wood" — the answer to v3\'s question: the deceitful tongue deserves YHWH\'s sharpened arrows and the fierce burning coals of broom wood (<em>rĕtāmîm</em>). <em>rōtem</em> (broom shrub, Retama raetam) — a desert shrub; its charcoal burns with exceptional, sustained heat. The image evokes YHWH\'s warrior arsenal (Ps 7:13; 18:14). The lying tongue has committed a war against the psalmist; it will be met with divine military response.</p>',
    "5": '<p><strong>ʾôy-lî kî-gartî mešek šākantî ʿim-ʾohălê qēdār</strong> — "woe is me that I sojourn in Meshech, that I dwell among the tents of Kedar!" — <em>Meshech</em> appears in the Table of Nations (Gen 10:2) as a son of Japheth; associated with Anatolia (modern Turkey). <em>Kedar</em> (Gen 25:13) was a son of Ishmael; the Kedarites were semi-nomadic tribes of the Arabian desert. Together Meshech + Kedar represent the antipodes of the known world — the farthest possible distance from Jerusalem. This may be figurative for hostile pagans rather than geographic precision: the pilgrim feels exiled among those whose values are irreconcilably alien to covenant life.</p>',
    "6": '<p><strong>rabbat šākenāh-llāh napšî ʿim śōnēʾ šālôm</strong> — "too long has my soul dwelt with those who hate peace" — <em>rabbat</em> (much, many, too long) — the accumulation of time among peace-haters has become intolerable. <em>śōnēʾ šālôm</em> (those who hate peace) — the compound noun-hater is not merely indifferent but actively hostile to <em>šālôm</em> (wholeness, well-being, covenant flourishing). This sets up the starkly personal antithesis of v7.</p>',
    "7": '<p><strong>ʾănî-šālôm ûkî ʾădabbēr hēmmāh lammilḥāmāh</strong> — "I am peace (= for peace); but when I speak, they are for war" — the most compressed verse in the psalm. The Hebrew is jarring: <em>ʾănî šālôm</em> (I am peace) — the psalmist does not merely desire peace but identifies himself with it. The word order emphasizes the contrast: I = peace / they = war. The moment of speech becomes the flashpoint: the very act of speaking peace provokes war. The phrase anticipates Christ\'s beatitude on the peacemakers (Matt 5:9) and Paul\'s description of the gospel as the "good news of peace" (Eph 6:15).</p>',
  },
  "121": {
    "1": '<p><strong>ʾeśśāʾ ʿênay ʾel-hehārîm mēʾayin yābōʾ ʿezrî</strong> — "I lift my eyes toward the hills — but where does my help come from?" — the question mark is crucial; the verse is a genuine question, not an affirmation. The hills are not the source of help: the pagan high places (<em>bāmôt</em>) were located on hills, and lifting eyes to the hills might evoke idolatrous worship. The pilgrim raises the question deliberately — and immediately answers it in v2: my help is not from the hills but from the one who made them. The Ascents setting (the pilgrim traveling toward Jerusalem) lends this a pilgrimage urgency.</p>',
    "2": '<p><strong>ʿezrî mēʿim yhwh ʿōśēh šāmayim wāʾāreṣ</strong> — "my help comes from the LORD, the maker of heaven and earth" — the answer to v1\'s question. <em>ʿōśēh šāmayim wāʾāreṣ</em> (maker of heaven and earth) — the same divine title as Ps 115:15, 124:8. The hills are part of the created order (earth); the LORD made them. Therefore the one who made the hills is greater than the hills; looking to the hills and then to their Maker is the psalm\'s theological argument. The participle <em>ʿōśēh</em> (ongoing making/sustaining) suggests not just original creation but active maintenance.</p>',
    "3": '<p><strong>ʾal-yittēn lammôṭ raglĕkā ʾal-yānûm šōmĕrekā</strong> — "he will not let your foot slip; your keeper will not slumber" — <em>šōmēr</em> (keeper, guardian, watchman) appears here for the first of six times in eight verses — a structural concentration unique in the Psalter. <em>yānûm</em> (to slumber, nod off, doze) — a light, momentary sleep. The distinction between <em>nûm</em> (doze) and <em>yāšan</em> (full sleep, v4) is deliberate: God neither dozes for a moment nor falls into full sleep. The foot not slipping is both literal (rocky Judean terrain on the ascent to Jerusalem) and metaphorical (moral stumbling in covenant life).</p>',
    "4": '<p><strong>hinnēh lōʾ-yānûm wĕlōʾ yîšān šômēr yiśrāʾēl</strong> — "See — he who guards Israel will neither slumber nor sleep" — the emphatic particle <em>hinnēh</em> (behold, look!) draws attention. <em>lōʾ-yānûm wĕlōʾ yîšān</em> — the double negation with two different sleep-words is emphatic: neither momentary dozing nor full sleep. The transition from the individual ("your keeper," v3) to the corporate ("keeper of Israel") situates the personal assurance within the covenant people as a whole — this is the LORD who never took his eye off Israel through the wilderness, the judges period, and the exile.</p>',
    "5": '<p><strong>yhwh šōmĕrekā yhwh ṣillĕkā ʿal-yad yĕmînĕkā</strong> — "the LORD is your keeper; the LORD is your shade at your right hand" — <em>ṣēl</em> (shade, shadow) — in the ancient Near Eastern sun, shade was not comfort but survival. The divine shade is a metaphor for protective covering (Ps 91:1; Num 14:9 uses lack of shade for an unprotected enemy). <em>ʿal-yad yĕmînĕkā</em> (at your right hand) — the right hand is the position of the defender in battle (Ps 16:8; 109:31). The LORD-as-shade stands at the right hand of the pilgrim, between them and the blazing threat.</p>',
    "6": '<p><strong>yômām haššemeš lōʾ-yakkĕkāh wĕyārēaḥ ballaylāh</strong> — "the sun will not strike you by day, nor the moon by night" — <em>nākāh</em> (to strike, smite) — the verb used for the plagues of Egypt (Exod 3:20). In the ancient world both solar heat and moonlight were thought to cause illness (sun-stroke, moon-stroke/lunacy). The psalm does not endorse these beliefs but uses them to frame a comprehensive protection: whatever threatens from above — day and night, sun and moon — the LORD\'s shade covers.</p>',
    "7": '<p><strong>yhwh yišmāreĕkā mikkol-rāʿ yišmōr ʾet-napšĕkā</strong> — "the LORD will protect you from all evil; he will guard your very life/soul" — <em>kol-rāʿ</em> (all evil/harm) — the comprehensive scope: not merely physical dangers but every category of harm. <em>napšĕkā</em> (your life, your soul, your whole self) — <em>nepeš</em> here is not merely the spiritual soul but the whole living person. The LORD\'s keeping reaches to the core of the person, not merely the exterior.</p>',
    "8": '<p><strong>yhwh yišmōr-ṣēʾtĕkā ûbôʾekā mēʿattāh wĕʿad-ʿôlām</strong> — "the LORD will watch over your coming and going, now and forever" — <em>ṣēʾtĕkā ûbôʾekā</em> (your going out and your coming in) — a merism for all of life\'s movements: leaving and returning, the whole circuit of daily existence. Deut 28:6 uses the same formula for the covenant blessing ("blessed shall you be when you come in, and blessed when you go out"). The temporal span <em>mēʿattāh wĕʿad-ʿôlām</em> (from now and unto eternity) matches Ps 113:2 and 115:18 — closing the pilgrim psalm with the eschatological horizon of Hallel praise.</p>',
  },
  "122": {
    "1": '<p><strong>śāmaḥtî bĕʾōmĕrîm lî bêt yhwh nēlēk</strong> — "I rejoiced when they said to me, \'Let us go to the house of the LORD!\'" — the verb <em>śāmaḥtî</em> (I rejoiced, Qal perfect) is inceptive: "I broke into joy." The invitation from the plural ("they said to me") is the first moment of the pilgrimage experience — the community calling the individual into the journey. <em>bêt yhwh</em> (house of the LORD) — the temple, YHWH\'s royal dwelling on Zion. The superscription names David as author, placing this joy in the context of David\'s longing to build the temple (2 Sam 7).</p>',
    "2": '<p><strong>ʿōmĕdôt hāyû raglênû bišʿārayik yĕrûšālāim</strong> — "our feet are standing within your gates, O Jerusalem!" — the perfect tense <em>hāyû</em> (have been/are) with the present participle <em>ʿōmĕdôt</em> (standing) creates a vivid present: the feet that were journeying now stand inside the city. The direct address to Jerusalem ("your gates") personifies the city. The gates (<em>šĕʿārîm</em>) were the legal, commercial, and social hub of ancient cities — the pilgrim\'s feet standing in the gates signal full arrival.</p>',
    "3": '<p><strong>yĕrûšālayim habbĕnûyāh kĕʿîr šeḥubbĕrāh-llāh yaḥdāw</strong> — "Jerusalem — built as a city that is closely joined/compact together" — <em>šeḥubbĕrāh-llāh yaḥdāw</em> (that is joined together as one) — the Pual participle of <em>ḥābar</em> (to join, couple, unite). The architectural compactness of Jerusalem — its dense stone buildings and close-packed topography — becomes a metaphor for the unity of the covenant people who gather there. The phrase may also reflect the joining of the two kingdoms (Judah and Israel) in pilgrimage to the shared sanctuary.</p>',
    "4": '<p><strong>šeššām ʿālû šĕbāṭîm šibṭê-yāh ʿēdût lĕyiśrāʾēl lĕhôdôt lĕšēm yhwh</strong> — "to which the tribes go up — the tribes of the LORD — as a testimony for Israel, to give thanks to the name of the LORD" — <em>šibṭê-yāh</em> (tribes of the LORD, with the divine shortform Yah) — the tribes belong to YHWH, not merely to their geographical territories. <em>ʿēdût</em> (testimony, statute) — the command to appear before the LORD at the festivals (Exod 23:17; 34:23) is here called a testimony/statute. <em>lĕhôdôt</em> (to give thanks/praise, Hiphil infinitive of <em>yādāh</em>) — the purpose of the pilgrimage is thanksgiving.</p>',
    "5": '<p><strong>kî-šāmmāh yāšĕbû kissĕʾôt lĕmišpāṭ kissĕʾôt lĕbêt dāwid</strong> — "for there the thrones of judgment stand — the thrones belonging to the house of David" — <em>kissĕʾôt lĕmišpāṭ</em> (thrones for judgment) — the judicial seat of the Davidic king was in Jerusalem; the pilgrimage center was also the royal court for legal appeals (cf. 2 Sam 15:1-6; 1 Kgs 7:7). The plural <em>kissĕʾôt</em> (thrones) may refer to multiple courtrooms or the dynasty\'s collective judicial presence. The Davidic kingship and the temple worship are here inseparably linked.</p>',
    "6": '<p><strong>šaʾălû šĕlôm yĕrûšālāim yišlāyû ʾōhăbāyik</strong> — "pray for the peace of Jerusalem! May all who love this city flourish" — the triple wordplay: <em>šaʾălû</em> (ask/pray) + <em>šĕlôm</em> (peace/shalom) + <em>yĕrûšālāim</em> (Jerusalem) — the city\'s very name may be heard as <em>yĕrû-šālēm</em> (city of peace), making the command to pray for its peace a play on its identity. <em>yišlāyû</em> (may they be at ease, prosper, have security, from <em>šālāh</em>, to be at ease) — those who love Jerusalem will share in the shalom they pray for.</p>',
    "7": '<p><strong>yĕhî-šālôm bĕḥêlēk šalwāh bĕʾarmĕnôtāyik</strong> — "may there be peace within your walls and safety within your strongholds/citadels" — <em>ḥêlēk</em> (your walls, ramparts, from <em>ḥēl</em> = outer wall or moat) — the first line of the city\'s defense. <em>šalwāh</em> (safety, ease, prosperity) — a near synonym of <em>šālôm</em>, continuing the sound-cluster. <em>ʾarmĕnôtāyik</em> (your palaces, citadels, towers) — the innermost defended structures. The movement from outer walls to inner palaces maps the prayer\'s scope from the perimeter to the heart of the city.</p>',
    "8": '<p><strong>lĕmaʿan ʾaḥay wĕrēʿāy ʾădabbĕrāh-nnāʾ šālôm bāk</strong> — "for the sake of my brothers and friends I now say, \'Peace be with you!\'" — the psalmist\'s motivation is relational: the prayer for peace is not nationalist sentiment but affection for the <em>ʾaḥim</em> (brothers) and <em>rēʿîm</em> (friends/companions) who share the pilgrimage. The address <em>bāk</em> (in/with you) is to Jerusalem, confirming the personification of the city throughout the psalm.</p>',
    "9": '<p><strong>lĕmaʿan bêt-yhwh ʾĕlōhênû ʾăbaqqĕšāh ṭôb lāk</strong> — "for the sake of the house of the LORD our God I will work for your wellbeing" — the final motivation: the welfare of Jerusalem is sought because YHWH\'s house is there. <em>ʾăbaqqĕšāh ṭôb</em> (I will seek good) — active pursuit, not passive wishing. The psalm ends with the divine presence (the house of the LORD) as the ultimate ground for all the peace-praying that precedes it. Jerusalem matters because YHWH has chosen it as his dwelling.</p>',
  },
  "123": {
    "1": '<p><strong>ʾēlêkā nāśāʾtî ʾet-ʿênay hayyōšĕbî baššāmāyim</strong> — "to you I lift my eyes, O you who sit enthroned in the heavens!" — the opening gesture (lifting eyes) echoes Ps 121:1 but with a crucial difference: here the eyes are lifted directly to YHWH, not ambiguously toward the hills. <em>hayyōšĕbî baššāmāyim</em> (the one who sits/is enthroned in the heavens) — the divine title stresses sovereign rule from above; this is the same God who bent down to look in Ps 113:6. The pilgrim looks up to find the one who has already looked down.</p>',
    "2": '<p><strong>hinnēh kĕʿênê ʿăbādîm ʾel-yad ʾădônêhem kĕʿênê šipḥāh ʾel-yad gĕbirtāh kēn ʿênênû ʾel-yhwh ʾĕlōhênû ʿad šeyĕḥānnēnû</strong> — the sustained analogy of master/servant and mistress/maidservant. The servant watches the master\'s hand (<em>yad</em>) — in the ancient household economy, a subtle gesture of the master\'s hand gave the servant instructions without words. The servant\'s whole attention is on the hand that may signal need or command. <em>ʿad šeyĕḥānnēnû</em> (until he has mercy on us) — the waiting is not passive but attentive, watchful. The plural <em>ʿênênû</em> (our eyes) shifts to the whole congregation.</p>',
    "3": '<p><strong>ḥānnēnû yhwh ḥānnēnû kî-rab śābaʿnû bûz</strong> — "have mercy on us, O LORD, have mercy on us — for we have endured far more than our fill of contempt" — the doubled <em>ḥānnēnû</em> (have mercy on us / be gracious to us) is urgent petition. <em>rab śābaʿnû bûz</em> (we are exceedingly filled with contempt) — <em>bûz</em> (contempt, scorn, despising) is a cutting social wound, worse than hostility: to be despised is to be treated as of no account. <em>śābaʿnû</em> (we are filled/sated) — as one becomes surfeited with food, the psalmist is surfeited with contempt; they have had more than enough.</p>',
    "4": '<p><strong>rabbat śābeʿāh lāh napšēnû hallaʿag haššaʾănannîm habbûz ligĕʾônîm</strong> — "we have had more than our fill of the mockery of the comfortable and the contempt of the arrogant" — <em>laʿag</em> (mockery, derision, scorn) from <em>lāʿag</em>, to mock, stammer at. <em>šaʾănannîm</em> (those at ease, the comfortable, the prosperous) — the word ironically echoes <em>šaʾănān</em> (ease, security); those who are comfortable mock the pilgrim community. <em>gĕʾônîm</em> (the proud, arrogant, from <em>gāʾah</em>, to be high, exalted) — pride and ease together: the psalm identifies social contempt as coming from those whose comfort makes them forget their own contingency.</p>',
  },
  "124": {
    "1": '<p><strong>lûlê yhwh šehāyāh lānû yōmar-nāʾ yiśrāʾēl</strong> — "if the LORD had not been on our side — let Israel say it now —" — the psalm opens with the liturgical invitation <em>yōmar-nāʾ yiśrāʾēl</em> (let Israel now say) — this is a communal confession, repeated by the assembly. The construction <em>lûlê</em> (if not, unless) introduces a contrary-to-fact conditional: what would have happened if YHWH had not intervened. The repeated <em>lûlê yhwh šehāyāh lānû</em> (vv1-2) creates emphasis through near-verbatim repetition.</p>',
    "2": '<p><strong>lûlê yhwh šehāyāh lānû bĕqûm ʿālênû ʾādām</strong> — "if the LORD had not been on our side when humans rose up against us" — <em>bĕqûm ʿālênû ʾādām</em> (when humans/mankind rose up against us) — the enemy is called <em>ʾādām</em> (humanity, mortal people) — not a demonic force but human opposition. The use of <em>ʾādām</em> rather than a specific ethnic group generalizes the threat while simultaneously diminishing it: these are mere mortals who rose against the people of YHWH.</p>',
    "3": '<p><strong>ʾăzay ḥayyîm bĕlaʿûnû bĕḥărôt ʾappām bānû</strong> — "then they would have swallowed us alive when their fury blazed against us" — <em>bĕlaʿûnû ḥayyîm</em> (swallowed us alive) — <em>bālaʿ</em> (to swallow, engulf, to be a void, to destroy; Jonah 1:17 uses the same word for the great fish). <em>ḥayyîm</em> (living/alive) — not merely destroyed but consumed while still alive, as Sheol is said to swallow the living in Prov 1:12. <em>ḥărôt ʾappām</em> (the burning/kindling of their nose-anger) — anger in Hebrew physiology is located in the nose (<em>ʾap</em>): the flaring of nostrils accompanies rage.</p>',
    "4": '<p><strong>ʾăzay hammayim šĕṭāpûnû naḥlāh ʿābar ʿal-napšēnû</strong> — "then the rushing waters would have swept us away; the current would have poured over our soul/life" — the metaphor shifts from predatory animal (v3) to flood. <em>mayim šĕṭāpûnû</em> (the waters swept over us) — <em>šāṭap</em> (to overflow, sweep away, rinse, inundate). <em>naḥlāh</em> (the torrent, wadi-stream) — the sudden flash floods of Palestinian wadis that sweep away everything in their path. <em>ʿal-napšēnû</em> (over our life/soul) — the waters threatening the <em>nepeš</em> (the living self).</p>',
    "5": '<p><strong>ʾăzay ʿābar ʿal-napšēnû hammayim hazzêdônîm</strong> — "then the raging/insolent waters would have overwhelmed us" — <em>hammayim hazzêdônîm</em> (the insolent/raging/proud waters) — <em>zādôn</em> (pride, presumptuousness, insolence, from <em>zûd</em>, to boil over, act presumptuously) — the same word used for human pride and arrogance (Jer 50:31-32). The waters are personified as proud and insolent — as if the flood itself had the character of the proud enemies of v4:4. This is not pathetic fallacy but theological characterization: chaos and pride share the same root.</p>',
    "6": '<p><strong>bārûk yhwh šellōʾ nĕtānānû ṭeref lĕšinnêhem</strong> — "blessed be the LORD, who did not give us as prey to their teeth!" — the doxology breaks the counter-factual conditional: the disasters of vv3-5 did not happen. <em>ṭeref lĕšinnêhem</em> (prey to their teeth) — the metaphor returns to the predatory animal image of v3 (swallowing alive). The enemies who would have swallowed them are now imagined as having teeth — a lion or wolf tearing prey. <em>bārûk yhwh</em> (blessed be the LORD) — the standard benediction formula for divine rescue (Gen 14:20; 1 Sam 25:39).</p>',
    "7": '<p><strong>napšēnû kĕṣippôr nimlĕṭāh mippah yôqĕšîm happah nišbar waʾănaḥnû nimlāṭnû</strong> — "our soul escaped like a bird out of the snare of the fowlers — the snare was broken, and we escaped" — <em>ṣippôr</em> (a sparrow, bird) — small and vulnerable; the standard image for the weak and endangered (Ps 11:1; Matt 10:29-31). <em>pah yôqĕšîm</em> (the snare of the fowlers/trappers) — <em>yāqôš</em> (fowler, bird-trapper) — those who set hidden traps for birds. <em>happah nišbar</em> (the snare was broken) — not the bird\'s skill but the snare\'s failure; the escape is YHWH\'s doing, not the bird\'s strength.</p>',
    "8": '<p><strong>ʿezrênû bĕšēm yhwh ʿōśēh šāmayim wāʾāreṣ</strong> — "our help comes from the name of the LORD, the maker of heaven and earth" — the closing verse echoes Ps 121:2 verbatim: <em>ʿōśēh šāmayim wāʾāreṣ</em> (maker of heaven and earth). Within the Songs of Ascents, this repetition creates an intentional bookend — the keeper of Israel (Ps 121) is the same one who breaks the snare (Ps 124). <em>bĕšēm yhwh</em> (in the name of the LORD) — the name as the mediating presence of YHWH, his revealed character acting on behalf of his people.</p>',
  },
  "125": {
    "1": '<p><strong>habbōṭĕḥîm bayhwāh kĕhar-ṣiyyôn lōʾ-yimmôṭ lĕʿôlām yēšēb</strong> — "those who trust in the LORD are as firm as Mount Zion — unmovable, abiding forever" — the simile places divine trust on par with the geological permanence of Zion. <em>bāṭaḥ</em> (to trust, be confident) is the covenant-confidence word throughout the Psalter. <em>lōʾ-yimmôṭ</em> (will not be shaken/moved, Niphal of <em>māṭaṭ</em>) — cf. Ps 112:6 (the righteous will not be moved). Mount Zion\'s permanence is YHWH\'s own choice (Ps 132:13-14) — those who trust YHWH share in the stability he has chosen for his dwelling place.</p>',
    "2": '<p><strong>yĕrûšālāim hārîm sābîb lāh wayhwāh sābîb lĕʿammô mēʿattāh wĕʿad-ʿôlām</strong> — "as the mountains encircle Jerusalem, so the LORD encircles his people, from now and forever" — the geographic simile is exact: Jerusalem sits in a basin surrounded by higher ridges (Mount of Olives, Mount Scopus, Mount Zion, Gihon valley). The surrounding mountains are the city\'s natural fortification. YHWH\'s encirclement of his people (<em>sābîb</em>, around, on all sides) is at least as complete as the mountains around Jerusalem — and permanent in a way mountains are not.</p>',
    "3": '<p><strong>kî lōʾ-yānûaḥ šēbeṭ hārāšāʿ ʿal gôral haṣṣaddîqîm lĕmaʿan lōʾ-yišlĕḥû haṣṣaddîqîm bĕʿawlāh yĕdêhem</strong> — "for the scepter of the wicked will not rest over the allotted territory of the righteous, lest the righteous put out their hands to do wrong" — <em>šēbeṭ hārāšāʿ</em> (the rod/scepter of the wicked) — political oppression by wicked rulers. <em>gôral haṣṣaddîqîm</em> (the allotment/lot of the righteous) — the land inheritance (<em>gôral</em>, the lot cast for tribal territories, Josh 14-19). The theological argument: prolonged oppression risks moral corruption of the oppressed — YHWH removes the oppressor not merely for justice but to protect the righteous from the temptation to adopt wicked means.</p>',
    "4": '<p><strong>hêṭîbāh yhwh laṭṭôbîm ûlĕyišārîm bĕlibbôtām</strong> — "do good, O LORD, to those who are good, and to those who are upright in their hearts" — the prayer <em>hêṭîbāh</em> (do good, Hiphil imperative of <em>yāṭab</em>) — an appeal for positive divine action following the negative protection of v3. <em>laṭṭôbîm</em> (to those who are good) and <em>lĕyišārîm bĕlibbôtām</em> (to those who are upright in their hearts) — the internal qualifier "in their hearts" distinguishes genuine uprightness from external conformity.</p>',
    "5": '<p><strong>wĕhammaṭṭîm ʿaqalqallôtām yôlîkēm yhwh ʾet-pōʿălê hāʾāwen šālôm ʿal-yiśrāʾēl</strong> — "but as for those who swerve onto crooked paths, the LORD will banish them along with those who do evil. Peace be upon Israel!" — <em>hammaṭṭîm ʿaqalqallôtām</em> (those who turn to their crooked ways) — <em>ʿaqalqal</em> (twisted, crooked, devious) — the word is an intensive form suggesting deeply bent, tortuous paths. <em>pōʿălê hāʾāwen</em> (workers of wickedness/iniquity) — the same phrase as Ps 6:8 and many other psalms. The closing <em>šālôm ʿal-yiśrāʾēl</em> (peace upon Israel) is the standard liturgical close of many Psalms of Ascents (cf. Ps 128:6; 131:3).</p>',
  },
  "126": {
    "1": '<p><strong>bĕšûb yhwh ʾet-šîbat ṣiyyôn hāyînû kĕḥōlĕmîm</strong> — "when the LORD restored the fortunes of Zion, we were like people in a dream" — <em>šûb ʾet-šĕbût</em> (the idiom "restore the fortunes/captivity") — the phrase appears ~27x in the OT; it likely means both "restore the fortunes" (general reversal of loss) and "return from captivity" (exile and return); both senses apply to the post-exilic community. <em>hāyînû kĕḥōlĕmîm</em> (we were like dreamers) — so sudden, so complete was the reversal that it seemed unreal. The simile does not mean they were asleep but that the restoration felt like the impossible come true.</p>',
    "2": '<p><strong>ʾāz yimmālēʾ śĕḥôq pînû ûlĕšônênû rinnāh ʾāz yōʾmĕrû baggôyim higgîl yhwh laʿăśôt ʿim-ʾēlleh</strong> — "then our mouths were filled with laughter and our tongues with shouts of joy; then the nations were saying, \'The LORD has done great things for them!\'" — <em>śĕḥôq</em> (laughter, joy, the sound of laughter) — not mirth at another\'s expense but the laughter of relief and wonder. <em>rinnāh</em> (shouts of joy, exultant singing) — the distinctive joy-shout of the sanctuary. Crucially, even the <em>gôyim</em> (nations) recognize what has happened: YHWH\'s action is visible enough that outsiders can see it and name its source.</p>',
    "3": '<p><strong>higgîl yhwh laʿăśôt ʿimmānû hāyînû śĕmēḥîm</strong> — "the LORD has done great things for us — and we are overjoyed" — the psalm quotes the nations\' speech (v2) and then adopts it as Israel\'s own confession. The verb <em>higgîl</em> (to do greatly, to act magnificently) in Hiphil — God\'s action is characterized by magnitude. <em>śĕmēḥîm</em> (joyful, glad) — the simple and direct emotional state that results from YHWH\'s great action. The brevity of v3 after the longer v2 is a poetic technique of emphasis: the main thing is stated cleanly.</p>',
    "4": '<p><strong>šûbāh yhwh ʾet-šĕbîtênû kāʾăpîqîm bannegeb</strong> — "restore our fortunes, O LORD, like the streams that suddenly fill the desert wadis" — the prayer <em>šûbāh ʾet-šĕbîtênû</em> (restore our fortunes/captivity) mirrors v1\'s <em>bĕšûb yhwh</em> (when the LORD restored) — the past restoration becomes the grounds for praying it again. <em>kāʾăpîqîm bannegeb</em> (like the wadis in the Negev) — the <em>ʾăpîqîm</em> (channels, stream-beds, wadis) of the Negev are bone-dry for most of the year but can fill with thunderous torrents in minutes when rain falls in the hills. The petition is for that kind of sudden, dramatic reversal.</p>',
    "5": '<p><strong>hazzōrĕʿîm bĕdimʿāh bĕrinnāh yiqṣōrû</strong> — "those who plant/sow in tears will harvest with shouts of joy" — the agricultural metaphor of sowing and reaping maps perfectly onto the exile/return pattern: the exile is the season of tears/planting; the return is the harvest of joy. <em>zāraʿ</em> (to sow, plant seed) — the farmer sowing in tears: perhaps the tears of depleted energy at day\'s end, or grief at the seeming impossibility of harvest, or the tears of repentance. <em>bĕrinnāh yiqṣōrû</em> (with shouts of joy they will reap) — future tense: this is still prophetic for some in the community.</p>',
    "6": '<p><strong>hālôk yēlēk ûbākkōh nōśēʾ mešek-hazāraʿ bōʾ-yābōʾ bĕrinnāh nōśēʾ ʾălumōtāyw</strong> — "the one who sets out weeping, carrying the seed bag, will come home with shouts of joy, loaded with his sheaves" — the infinitive absolute constructions (<em>hālôk yēlēk</em> = goes and goes, i.e. really goes out; <em>bōʾ-yābōʾ</em> = comes and comes, i.e. really does return) emphasize the certainty of both the going and the return. <em>mešek-hazāraʿ</em> (the seed bag/precious seed, lit. "drawn-out seed" or "trail of seed") — the precious seed carried with tears. <em>ʾălumōtāyw</em> (his sheaves, bundles of grain) — the return is loaded, arms full. The theological promise: no sowing in tears is wasted; every act of faithful obedience in a season of loss will have its harvest.</p>',
  },
  "127": {
    "1": '<p><strong>ʾim-yhwh lōʾ-yibneh bayit šāwĕʾ ʿāmĕlû bônāyw bô ʾim-yhwh lōʾ-yišmor-ʿîr šāwĕʾ šāqad šômēr</strong> — "unless the LORD builds the house, the builders labor in vain; unless the LORD guards the city, the sentinel watches for nothing" — <em>šāwĕʾ</em> (vanity, emptiness, futility, falsehood) — the same word used in the third commandment ("take the name of the LORD in vain," Exod 20:7). The attribution to Solomon (<em>lĕšĕlōmōh</em>) gives the verse a Solomon-temple resonance: the very temple Solomon built was only effective because YHWH chose to dwell in it (1 Kgs 8:27). <em>bayit</em> (house) has double force: the physical temple AND the Davidic dynasty ("your house shall be made sure," 2 Sam 7:11,16).</p>',
    "2": '<p><strong>šāwĕʾ lākem maškîmê qûm mĕʾaḥărê šebet ʾōkĕlê leḥem hāʾăṣābîm kēn yittēn lîdîdô šēnāʾ</strong> — "it is pointless for you to rise early, stay up late, eating the bread of anxious toil — for he gives sleep to those he loves" — <em>maškîmê qûm</em> (those who rise early, from <em>šāḵam</em>, to be early, start at dawn) — the pre-dawn laborer. <em>leḥem hāʾăṣābîm</em> (bread of sorrows/pain/anxious toil) — <em>ʿăṣab</em> (pain, toil, sorrow) — the curse vocabulary of Gen 3:16-17 (toil, pain, eating by sweat). <em>kēn yittēn lîdîdô šēnāʾ</em> — "for so he gives to his beloved sleep" — <em>dîdô</em> (his beloved, from <em>yādîd</em>, beloved, dear) — the beloved of YHWH. Sleep is not earned by exhaustion but given as a gift; the one who rests in YHWH\'s provision does not need to anxiously secure their own existence through sleepless toil.</p>',
    "3": '<p><strong>hinnēh naḥălat yhwh bānîm śākār pĕrî habbāṭen</strong> — "Yes, children are an inheritance from the LORD; they are a reward he gives" — <em>naḥălat yhwh</em> (the inheritance/heritage of the LORD) — children are not merely the product of human biology but a divine gift, a share in what the LORD distributes. <em>śākār</em> (reward, wages) — normally used for labor payment; here applied to the fruit of the womb, suggesting that children are the "wages" YHWH gives for covenant faithfulness rather than for anxious toil (cf. v2\'s bread of anxious toil → v3\'s inherited children).</p>',
    "4": '<p><strong>kĕḥiṣṣîm bĕyad-gibbôr kēn bĕnê hannĕʿûrîm</strong> — "children born in a man\'s prime are like arrows in the hand of a warrior" — <em>ḥiṣṣîm</em> (arrows) — the plural of <em>ḥēṣ</em> (arrow, from <em>ḥāṣaṣ</em>, to cut). <em>bĕnê hannĕʿûrîm</em> (sons of youth/the prime years, lit. "sons of the youthful ones") — children born when the father is young enough that they will be fully grown when he is old, providing protection in his vulnerability. The arrow metaphor: straight, well-prepared, directed with force. Arrows in the hand of a warrior are ready for deployment — these children are the father\'s defense in the vulnerable years.</p>',
    "5": '<p><strong>ʾašrê haggeber ʾăšer millēʾ ʾet-ašpātô mēhem lōʾ-yēbōšû kî-yĕdabbĕrû ʾet-ʾôyĕbîm baššāʿar</strong> — "blessed is the man who has his quiver full of them! He will not be put to shame when he confronts his enemies at the gate" — <em>ʾašpāh</em> (quiver, arrow-case) — the image completes the arrow metaphor. <em>baššāʿar</em> (at the gate) — the city gate was the judicial arena where legal disputes were settled; the man with grown sons standing beside him would have moral weight in legal proceedings and practical protection against false accusations.</p>',
  },
  "128": {
    "1": '<p><strong>ʾašrê kol-yĕrēʾ yhwh hahōlēk bidrākāyw</strong> — "blessed is every person who fears the LORD and walks in his ways" — Ps 128 is a companion beatitude to Ps 112 (both begin with <em>ʾašrê</em> and focus on the God-fearing man\'s flourishing). The universal <em>kol</em> (every, all) opens the blessing to any person, not just the head of household — though the psalm will develop the domestic picture. <em>hahōlēk bidrākāyw</em> (the one who walks in his ways) — the walking (<em>hālak</em>) metaphor for covenant life is Deuteronomic in origin (Deut 8:6; 10:12).</p>',
    "2": '<p><strong>yĕgîaʿ kappêkā kî tōʾkēl ʾašrêkā wĕṭôb lāk</strong> — "you will eat the fruit of your labor; you will be blessed, and things will go well for you" — <em>yĕgîaʿ kappêkā</em> (the toil/labor of your palms/hands) — <em>kap</em> (palm, hand, hollow of the hand) — the very hands that work. Contrasting with Ps 127:2 (which warns against anxious toil), Ps 128 says that the labor of the God-fearer is not vain labor but genuinely productive. The covenant blessing is concrete and physical: the hands that work will eat what they have produced.</p>',
    "3": '<p><strong>ʾeštĕkā kĕgepen pōriyyāh bĕyarkĕtê bêtĕkā bānêkā kĕšĕtîlê zêtîm sābîb lĕšulḥānĕkā</strong> — "your wife will be like a fruitful vine within your home; your children like young olive shoots around your table" — <em>gepen pōriyyāh</em> (a fruitful vine) — the vine bearing fruit in abundance; fertility imagery from the agricultural blessings of the land. <em>bĕyarkĕtê bêtĕkā</em> (within the innermost parts/sides of your house) — not a public display but flourishing in the domestic interior. <em>šĕtîlê zêtîm</em> (shoots/seedlings of olive trees) — young olives require years to mature but then produce abundantly for generations; the children are investments in the future, not merely present joys.</p>',
    "4": '<p><strong>hinnēh kî-kēn yĕbōrak gāber yĕrēʾ yhwh</strong> — "behold, thus shall the man be blessed who fears the LORD" — <em>hinnēh kî-kēn</em> (behold, for so, thus indeed) — the emphatic pointing-back formula: what was described in vv2-3 is precisely the content of the blessing. The verse functions as a summary and validation of the domestic vision: this is not an aspirational fantasy but the structural pattern of covenant life when lived from the fear of the LORD.</p>',
    "5": '<p><strong>yĕbārekkā yhwh miṣṣiyyôn ûrĕʾēh bĕṭûb yĕrûšālāim kōl yĕmê ḥayyêkā</strong> — "may the LORD bless you from Zion; may you see Jerusalem flourish all the days of your life" — the blessing source is <em>miṣṣiyyôn</em> (from Zion) — YHWH blesses from his chosen dwelling place. The connection between the domestic (wife and children, vv2-3) and the civic (Jerusalem) is deliberate: the individual household\'s flourishing is part of the city\'s flourishing and vice versa. <em>ûrĕʾēh bĕṭûb yĕrûšālāim</em> (and see the good of Jerusalem) — to live long enough to see the city well is itself a blessing.</p>',
    "6": '<p><strong>ûrĕʾēh-bānîm lĕbānêkā šālôm ʿal-yiśrāʾēl</strong> — "may you live to see your grandchildren. Peace be upon Israel" — <em>bānîm lĕbānêkā</em> (sons of your sons, i.e., grandchildren) — longevity enough to see the third generation. In the ancient world, dying before your grandchildren were born was a sign of divine disfavor; seeing them was the fullness of covenant blessing (Gen 50:23; Job 42:16). The closing <em>šālôm ʿal-yiśrāʾēl</em> (peace be upon Israel) — the standard liturgical coda of the Songs of Ascents (Ps 125:5; 131:3), extending the individual household\'s blessing to the whole people.</p>',
  },
  "129": {
    "1": '<p><strong>rabbat ṣĕrārûnî minnĕʿûray yōmar-nāʾ yiśrāʾēl</strong> — "many times they have afflicted me from my youth — let Israel say this now" — <em>rabbat</em> (many times, much, greatly) — the same opening word as Ps 123:4 (exceedingly filled). The liturgical call <em>yōmar-nāʾ yiśrāʾēl</em> (let Israel now say) echoes Ps 124:1 — this is Israel\'s communal testimony, not merely one individual\'s experience. <em>minnĕʿûray</em> (from my youth) — Israel personified as a nation from its origins (Egypt); the affliction has been lifelong, going back to the bondage in Egypt.</p>',
    "2": '<p><strong>rabbat ṣĕrārûnî minnĕʿûray gam lōʾ-yāklû lî</strong> — "many times they have afflicted me from my youth, and yet they have never overcome me" — the verbatim repetition of the first half-line followed by the crucial <em>gam lōʾ-yāklû lî</em> (yet they have not prevailed against me) — the adversative <em>gam</em> (and yet, even, also). The repeated oppression combined with the repeated non-defeat is the theological testimony: enemies are persistent, but YHWH is more persistent. <em>yākol</em> (to prevail, be able, overcome) — the enemies\' inability is the sign of divine protection.</p>',
    "3": '<p><strong>ʿal-gabbî ḥārĕšû ḥōrĕšîm hē ʾărîkû lĕmaʿănîtôtām</strong> — "they plowed across my back; they made long their furrows" — <em>ʿal-gabbî</em> (upon my back) — the metaphor of the plowed back is one of the Psalter\'s most vivid images of suffering; the back being plowed evokes flogging, where the stripes of the whip cut furrows in the flesh. <em>hē ʾărîkû lĕmaʿănîtôtām</em> (they made long their furrows) — extended, deep, deliberate furrows. The agricultural metaphor frames brutal violence in terms of cultivation — the oppressors turn Israel\'s back into their field, treating the people as the ground for their own purposes.</p>',
    "4": '<p><strong>yhwh ṣaddîq qiṣṣēṣ ʿăbôt rĕšāʿîm</strong> — "the LORD is righteous; he has cut through the ropes of the wicked" — <em>ṣaddîq</em> (righteous) — YHWH\'s righteousness here is his active justice on behalf of the wronged. <em>qiṣṣēṣ</em> (he cut, severed, Piel of <em>qāṣaṣ</em>) — the cutting is decisive and complete. <em>ʿăbôt rĕšāʿîm</em> (the cords/ropes of the wicked) — the ropes by which the wicked bound Israel, binding them to the plow (cf. v3\'s furrow). The image now inverts: the plowed field becomes the bound ox, and YHWH cuts the yoke-cords.</p>',
    "5": '<p><strong>yēbōšû wĕyissōgû ʾāḥôr kōl śōnĕʾê ṣiyyôn</strong> — "may every one who hates Zion be put to shame and driven back" — the psalm shifts from testimony (vv1-4) to imprecation (vv5-8). <em>yēbōšû</em> (may they be ashamed, Qal jussive of <em>bôš</em>) — shame is the social opposite of honor in the ancient Near Eastern world; to be shamed is to be publicly exposed as having no standing. <em>yissōgû ʾāḥôr</em> (may they be driven back, retreating backwards) — the military image of an army in rout, retreating without turning to fight.</p>',
    "6": '<p><strong>yihyû kĕḥăṣîr gakkôt šeqĕdem šālap yābeš</strong> — "may they be like grass growing on a flat rooftop, which withers before it even has a chance to grow" — <em>ḥăṣîr gakkôt</em> (the grass of rooftops/flat roofs) — the flat mud-brick roofs of ancient Palestine had cracks into which seeds blew; grass would sprout briefly in the rainy season but wither almost immediately in the dry season — no deep roots, no shade, no harvest. <em>šeqĕdem šālap yābeš</em> (which before it is drawn out, it withers) — before it even reaches maturity, before anyone could think of harvesting it, it shrivels. The image answers the plowing of v3: their "harvest" from Israel\'s back will produce nothing.</p>',
    "7": '<p><strong>šellōʾ millēʾ kappô qôṣēr wĕḥiṣnô mĕʿammēr</strong> — "no reaper fills his hand with it, and no one gathers it into sheaves" — the harvest imagery completes the agricultural metaphor: the rooftop-grass gives no handful to the reaper (<em>qôṣēr</em>) and no armful (<em>ḥōṣen</em>) to the one binding sheaves (<em>mĕʿammēr</em>). The wicked who plowed Israel\'s back hoping for a harvest will be like this futile rooftop grass — their effort produces absolutely nothing worth gathering.</p>',
    "8": '<p><strong>wĕlōʾ ʾāmĕrû hāʾōbĕrîm birkăt-yhwh ʾălêkem bērăknû ʾetkem bĕšēm yhwh</strong> — "and no one passing by will say, \'The LORD\'s blessing be on you! We bless you in the name of the LORD\'" — the standard blessing exchanged between reapers and those passing by during harvest (Ruth 2:4: Boaz greets the reapers: "The LORD be with you!" and they reply: "The LORD bless you!"). The absence of this exchange signals total failure: there is nothing to bless, no harvest to celebrate, no encounter of generosity between the field and the passerby. The wicked will not even receive the customary pleasantries of a good harvest — because there is none.</p>',
  },
  "130": {
    "1": '<p><strong>mimaʿămaqîm qĕrāʾtîkā yhwh</strong> — "from the depths I cry to you, O LORD" — <em>maʿămaqîm</em> (depths, plural of <em>māʿāmaq</em>, from <em>ʿāmaq</em>, to be deep) — the absolute bottom, the lowest imaginable point; used of deep waters (Ps 69:2,14; 88:7), and here of existential distress. The cry is upward from the bottom: YHWH is above; the psalmist is below. The Latin translation <em>de profundis</em> gave this psalm its traditional liturgical name. The singular voice of v1 broadens in vv7-8 to include all Israel — individual experience becomes communal.</p>',
    "2": '<p><strong>ʾădōnāy šimʿāh bĕqôlî tihyênāh ʾoznêkā qaššûbôt lĕqôl taḥănûnāy</strong> — "Lord, hear my voice; let your ears be attentive to my pleading voice" — the address shifts from <em>yhwh</em> (the covenant name, v1) to <em>ʾădōnāy</em> (the sovereignty name) — the psalmist addresses YHWH\'s lordship now rather than covenant relationship. <em>qaššûbôt</em> (attentive, listening, Qal participle of <em>qāšab</em>, to pay attention, prick up the ears) — the ears tuned and oriented toward the prayer. <em>taḥănûnāy</em> (my supplications, pleas for grace/mercy, from <em>ḥānan</em>) — same word as Ps 116:1; 28:2.</p>',
    "3": '<p><strong>ʾim-ʿăwōnôt tišmār-yāh ʾădōnāy mî yaʿămōd</strong> — "if you, O LORD, kept a record of sins, Lord, who could stand?" — <em>šāmar ʿăwōnôt</em> (to keep/guard/watch iniquities) — to maintain a legal ledger of sins. <em>mî yaʿămōd</em> (who would stand?) — to "stand" before God is to survive the court\'s verdict, to remain upright in judgment. The rhetorical question expects the answer: no one. The statement is profoundly theological: if divine mercy were replaced by strict accounting, even the most righteous person would be unable to stand. This anticipates Paul\'s argument in Romans 3.</p>',
    "4": '<p><strong>kî-ʿimĕkā hassĕlîḥāh lĕmaʿan tiwwārēʾ</strong> — "but forgiveness is found with you — and that is why you are held in awe" — <em>sĕlîḥāh</em> (forgiveness, pardon) — appears only three times in the OT: here, Neh 9:17, and Dan 9:9 — all in contexts of profound penitence before YHWH. The rarity marks it as a significant, non-routine word. The startling theological argument: YHWH is feared (<em>yārēʾ</em>) precisely because he forgives, not because he judges. If he maintained strict accounts (v3), he would terrify. But his forgiveness produces a deeper awe — the awe of the one who knows they have been spared.</p>',
    "5": '<p><strong>qiwwîtî yhwh qiwĕtāh napšî ûlidĕbārô hôḥāltî</strong> — "I wait for the LORD — my whole being waits — and in his word I put my hope" — <em>qāwāh</em> (to wait, hope, expect, look for — from a root meaning to stretch like a cord toward something) — intense, expectant waiting. The doubled verb (<em>qiwwîtî</em> + <em>qiwĕtāh napšî</em>) with the soul (<em>nepeš</em>) as subject: not only the mind but the whole living person is stretched toward YHWH. <em>lidĕbārô hôḥāltî</em> (in his word I hope, Hiphil of <em>yāḥal</em>) — YHWH\'s spoken word is the ground of the hope; this is not wishful thinking but expectation anchored in promise.</p>',
    "6": '<p><strong>napšî layhwāh miššōmĕrîm labboqer šōmĕrîm labboqer</strong> — "my soul waits for the LORD more than those who watch for the morning, more than those who watch for the morning" — <em>šōmĕrîm labboqer</em> (those who watch for the morning, dawn-sentinels) — night watchmen on the city walls who wait for the first light of dawn to signal the end of their vigilance. The comparison and its repetition: the psalmist\'s longing for YHWH is more intense than the watchman\'s longing for dawn. The repeated phrase ("more than those who watch for the morning... those who watch for the morning") is unusual — the MT double-occurrence is generally considered deliberate emphasis, not scribal error.</p>',
    "7": '<p><strong>yaḥēl yiśrāʾēl ʾel-yhwh kî-ʿim-yhwh haḥesed wĕharbēh ʿimmô pĕdût</strong> — "O Israel, put your hope in the LORD, for with the LORD is steadfast love, and with him is abundant redemption" — the psalm broadens from individual (vv1-6) to communal address. <em>haḥesed</em> (the steadfast love, with the definite article — this specific, well-known <em>ḥesed</em>) + <em>harbēh pĕdût</em> (abundant/plentiful redemption) — <em>pĕdût</em> (redemption by payment, from <em>pādāh</em>) with the adjective <em>harbēh</em> (much, abundant) — not merely one act of redemption but overflowing redemption. The contrast with v3: YHWH could keep accounts (mī yaʿămod = no one), but instead he offers abundant redemption.</p>',
    "8": '<p><strong>wĕhûʾ yipdeh ʾet-yiśrāʾēl mikkōl ʿăwōnōtāyw</strong> — "he will redeem Israel from all its sins" — the comprehensive scope: <em>kōl ʿăwōnōtāyw</em> (all its iniquities) — the same word as v3\'s ʿăwōnôt (iniquities kept on record). What YHWH chose not to keep as a legal record (v3) he will instead redeem (<em>pādāh</em>, ransom, buy out). The movement of the psalm: from the depths of sin (v1) → impossible standing under strict accounting (v3) → forgiveness (v4) → waiting (vv5-6) → communal hope (v7) → comprehensive redemption (v8). The psalm is a miniature Gospel: sin, judgment, mercy, hope, redemption.</p>',
  },
  "131": {
    "1": '<p><strong>yhwh lōʾ-gābah libbî wĕlōʾ-rāmû ʿênay wĕlōʾ-hālaktî bigdōlôt ûbĕniplāʾôt mimmennî</strong> — "LORD, my heart is not proud; my eyes are not lifted up in arrogance; I do not walk in matters too great or too marvelous for me" — the three negations form a triple self-renunciation. <em>gābah lēb</em> (proud heart, lit. "the heart is high") — the opposite of the humble heart that fears the LORD (Prov 16:5). <em>rāmû ʿênay</em> (my eyes are lifted, i.e., haughty eyes) — the high look of arrogance (Ps 18:27). <em>niplāʾôt</em> (wonders, things too wonderful/marvelous for me) — the same word used for YHWH\'s wondrous works (Ps 111:4; Job 42:3); the psalmist deliberately steps back from presuming to comprehend what belongs to divine mystery.</p>',
    "2": '<p><strong>ʾim-lōʾ šiwwîtî wĕdômamtî napšî kĕgāmûl ʿălê ʾimmô kĕgāmûl ʿālay napšî</strong> — "surely I have settled and silenced my soul; like a weaned child resting with its mother — like a weaned child, my soul is at rest within me" — <em>šiwwîtî</em> (I have stilled, made even, leveled — Piel of <em>šāwāh</em>) + <em>dômamtî</em> (I have silenced, made quiet — Hiphil of <em>dāmam</em>). <em>kĕgāmûl ʿălê ʾimmô</em> (like a weaned child with/upon his mother) — the key word is <em>gāmûl</em> (weaned child, from <em>gāmal</em>, to wean, also "to deal fully, to recompense"). A weaned child is no longer crying for milk — it has moved beyond the urgency of infancy into a resting relationship. The child rests not because it has received what it wanted but because the relationship itself is enough. This is the psalm\'s whole theology: the soul quieted not by receiving everything it desired but by settling into YHWH\'s presence without demand.</p>',
    "3": '<p><strong>yaḥēl yiśrāʾēl ʾel-yhwh mēʿattāh wĕʿad-ʿôlām</strong> — "O Israel, put your hope in the LORD, now and forever" — the closing call to Israel echoes Ps 130:7 verbatim (the same <em>yaḥēl yiśrāʾēl ʾel-yhwh</em>), creating a doublet between the two psalms. The individual soul\'s quieting (v2) becomes the model for Israel\'s collective posture: the nation is called to the same weaned-child rest in the LORD. <em>mēʿattāh wĕʿad-ʿôlām</em> (from now and unto eternity) — the standard eschatological formula (Ps 113:2; 115:18; 121:8) extends this quiet trust into permanent reality.</p>',
  },
  "132": {
    "1": '<p><strong>zĕkōr-yhwh lĕdāwid ʾēt kol-ʿunnôtô</strong> — "O LORD, remember David — remember all his hardships" — <em>zĕkōr</em> (remember, Qal imperative) — divine remembering always entails divine action (cf. Gen 8:1, Exod 2:24). The prayer is for YHWH to act based on David\'s afflictions. <em>ʿunnôtô</em> (his afflictions, hardships, from <em>ʿānāh</em>, to be humbled, afflicted, bowed down) — the same root as the verb for Israel\'s affliction in Egypt (Exod 1:11-12). David\'s devotion to the ark, and his "affliction" in pursuing YHWH\'s house, is presented as the grounds for YHWH\'s ongoing faithfulness to the Davidic dynasty.</p>',
    "2": '<p><strong>ʾăšer nišbaʿ layhwāh nādar lāʾăbîr yaʿăqōb</strong> — "how he made a solemn oath to the LORD and vowed to the Mighty One of Jacob" — <em>ʾăbîr yaʿăqōb</em> (the Mighty One of Jacob) — a rare divine title appearing in Gen 49:24 (Jacob\'s blessing of Joseph), Isa 49:26, 60:16 — it emphasizes YHWH\'s power/might (<em>ʾabbîr</em> = bull-strength, power). The title connects the Davidic covenant to the Abrahamic-Jacobite patriarchal promise.</p>',
    "3": '<p><strong>ʾim-ʾābōʾ bĕʾōhel bêtî ʾim-ʾeʿeleh ʿal-ʿereś yĕṣûʿāy</strong> — "I will not enter my house, nor climb into my bed" — the vow is structured as two negative conditionals: ʾim-ʾābōʾ (if I enter... [I am forsworn]) — the conditional oath formula. David vowed not to allow himself the comfort of his own dwelling until he had secured a dwelling for YHWH. The historical reference is to David\'s desire to build the temple (2 Sam 7:1-3), though the ark-finding narrative in vv6 suggests a different specific moment (2 Sam 6 or 1 Chr 13).</p>',
    "4": '<p><strong>ʾim-ʾettēn šĕnat lĕʿênāy lĕʿapʿappay tĕnûmāh</strong> — "I will allow no sleep to my eyes, no slumber to my eyelids" — <em>ʿapʿappayim</em> (eyelids, from <em>ʿûp</em>, to fly, flutter — the fluttering movement of eyelids) — a vivid anatomical term for the eyelids. The sleep deprivation vow (no sleep to eyes, no slumber to eyelids) reflects the urgency of the task. Ironically, YHWH is the one who neither slumbers nor sleeps (Ps 121:3-4) — David\'s vow imitates divine vigilance for the sake of YHWH\'s dwelling.</p>',
    "5": '<p><strong>ʿad-ʾemṣāʾ māqôm layhwāh mišĕkānôt lāʾăbîr yaʿăqōb</strong> — "until I find a fitting place for the LORD — a dwelling for the Mighty One of Jacob" — <em>māqôm</em> (place, site) + <em>mišĕkānôt</em> (dwelling places, tabernacles, from <em>šākan</em>, to dwell, settle) — the repeated word-family behind the tabernacle/Shekinah concept. David\'s goal is a permanent <em>māqôm</em> for YHWH to settle (<em>šākan</em>), replacing the mobile tent of the wilderness. The title <em>ʾăbîr yaʿăqōb</em> (Mighty One of Jacob) appears for the second time in two verses — the structural echo stresses the Abrahamic-Davidic continuity.</p>',
    "6": '<p><strong>hinnēh-šĕmaʿănûhā bĕʾeprātāh mĕṣāʾnûhā biśdê-yāʿar</strong> — "we heard of the ark at Ephrathah; we discovered it in the fields of Jaar" — <em>Ephrathah</em> = Bethlehem/its region (Gen 35:19; Mic 5:2) — the ark was associated with Kiriath-jearim (= Jaar, city of forests), where it had rested for 20 years after being returned from the Philistines (1 Sam 7:1-2). The "hearing" and "finding" suggest a community knowledge of where the ark was before the grand procession of 2 Sam 6. <em>biśdê-yāʿar</em> (in the fields of Jaar) — the wooded region around Kiriath-jearim.</p>',
    "7": '<p><strong>nābôʾāh lĕmišĕkĕnôtāyw niştaḥăweh lahadōm raglāyw</strong> — "let us go to his dwelling place; let us bow down at his footstool" — <em>mišĕkĕnôtāyw</em> (his dwelling places) — YHWH\'s dwelling, using the <em>šākan</em> root again. <em>hadōm raglāyw</em> (his footstool) — the ark was described as YHWH\'s footstool (1 Chr 28:2; Ps 99:5), the place where the divine feet "rested" on earth. Prostration before the footstool is prostration before the King on the throne above.</p>',
    "8": '<p><strong>qûmāh yhwh limnûḥātĕkā ʾattāh wĕʾărôn ʿuzzĕkā</strong> — "arise, O LORD, to your resting place — you and the ark that holds your power" — <em>qûmāh</em> (arise, Qal imperative of <em>qûm</em>) — the command to YHWH to arise echoes the ancient procession formula of Num 10:35 ("arise, O LORD, and let your enemies be scattered"). <em>limnûḥātĕkā</em> (to your resting place, from <em>nûaḥ</em>, to rest) — the Solomonic temple is envisioned as YHWH\'s permanent rest after the wandering years of the ark. <em>ʾărôn ʿuzzĕkā</em> (the ark of your strength/power) — not the ark of the covenant formula here but the ark of YHWH\'s <em>ʿōz</em> (might, power).</p>',
    "9": '<p><strong>kōhănêkā yilbĕšû-ṣedeq waḥăsîdêkā yĕrannēnû</strong> — "clothe your priests with righteousness, and let your devoted people shout for joy" — <em>yilbĕšû-ṣedeq</em> (may they be clothed with righteousness) — righteousness as a garment (cf. Isa 61:10; Job 29:14). The priests clothed with righteousness corresponds to the ark clothed with divine power (v8). <em>ḥăsîdêkā</em> (your devoted ones, your faithful ones, from <em>ḥesed</em>) — those who embody the covenant loyalty that YHWH has shown them. <em>yĕrannēnû</em> (let them shout for joy, from <em>rānan</em>, to cry aloud, shout with joy).</p>',
    "10": '<p><strong>baʿăbûr dāwid ʿabdĕkā ʾal-tāšēb pĕnê mĕšîḥĕkā</strong> — "for your servant David\'s sake, do not reject your anointed king" — <em>baʿăbûr</em> (for the sake of, because of) — the Davidic covenant as the ground of the prayer. <em>mĕšîḥĕkā</em> (your anointed, your Messiah) — the term that will carry the full weight of Messianic expectation; here it refers to the reigning Davidic king but within the covenant structure that points forward. The prayer not to "turn away the face" (<em>lōʾ tāšēb pĕnê</em>) of the anointed is a royal intercession.</p>',
    "11": '<p><strong>nišbaʿ yhwh lĕdāwid ʾĕmet lōʾ-yāšûb mimmennāh mippĕrî biṭnĕkā ʾāšît lĕkissēʾ-lāk</strong> — "the LORD made a true sworn covenant with David — he will never go back on it: \'I will place one of your own descendants upon your throne\'" — <em>ʾĕmet</em> (truth, faithfulness) — the oath is characterized by <em>ʾĕmet</em>; this is not a conditional covenant but a sworn unilateral commitment. <em>lōʾ-yāšûb mimmennāh</em> (he will not turn back from it) — the divine oath is irrevocable. <em>mippĕrî biṭnĕkā</em> (from the fruit of your body) — the physical Davidic line as the channel of the covenant promise (2 Sam 7:12-13; 16).</p>',
    "12": '<p><strong>ʾim-yišmĕrû bānêkā bĕrîtî wĕʿēdōtî zō ʾălammdēm gam-bĕnêhem ʿădê-ʿad yēšĕbû lĕkissēʾ-lāk</strong> — "if your sons keep my covenant and the decrees I teach them, their sons too shall sit upon your throne forever" — this conditional element (vv11b-12) appears to place conditions on the Davidic covenant, in tension with v11a\'s unconditional promise. The tension runs throughout 2 Sam 7 and Ps 89: YHWH will not abandon the Davidic line even when individual kings sin, but the dynasty\'s practical flourishing depends on covenant faithfulness. The NT resolution: the Messiah who perfectly keeps the covenant enables the permanent throne.</p>',
    "13": '<p><strong>kî-bāḥar yhwh bĕṣiyyôn ʾiwwāh lĕmôšāb lô</strong> — "the LORD has chosen Zion; he has made it his desired home" — <em>bāḥar</em> (to choose, elect) — the divine election of Zion parallels the divine election of David; both are unconditional acts of divine choice. <em>ʾiwwāh lĕmôšāb lô</em> (he desired it as a dwelling for himself) — <em>ʾāwāh</em> (to desire, long for, crave) — the language of passionate divine desire: YHWH longed for Zion as a home. This mutual longing (David for YHWH\'s ark, vv3-5; YHWH for Zion, v13) is the relational core of the Davidic covenant.</p>',
    "14": '<p><strong>zōʾt-mĕnûḥātî ʿădê-ʿad pōh-ʾēšēb kî ʾiwtîhāh</strong> — "\'This is my resting place forever; here I will live, for I have longed for it\'" — YHWH speaks directly for the first time in the psalm. <em>mĕnûḥātî ʿădê-ʿad</em> (my resting place unto eternity) — the permanent rest after the wandering of the wilderness and the period of the judges. <em>pōh-ʾēšēb</em> (here I will dwell/sit) — the divine declaration of permanent habitation. The echo of v8\'s <em>limnûḥātĕkā</em> (to your resting place) closes the circle: what the congregation prayed for (v8), YHWH now declares as his own settled intention (v14).</p>',
    "15": '<p><strong>ṣêdāh bārēk ʾăbārēk ʾebyônêhā ʾaśbîaʿ lāḥem</strong> — "I will richly bless her food supply; I will fill the poor with bread" — the divine promises flow from YHWH\'s choice of Zion. <em>ṣêdāh bārēk ʾăbārēk</em> (her provision I will bless abundantly, infinitive absolute construction) — the doubling of the verb (<em>bārēk ʾăbārēk</em>) for intensification: I will truly/abundantly bless. <em>ʾebyônêhā ʾaśbîaʿ lāḥem</em> (her poor I will satisfy with bread) — the social justice dimension of Zion\'s blessing: YHWH\'s presence ensures that the poor are fed (Ps 146:7; Luke 1:53 in the Magnificat).</p>',
    "16": '<p><strong>wĕkōhănêhā ʾalbiš yĕšaʿ waḥăsîdêhā rannēn yĕrannēnû</strong> — "I will clothe her priests with salvation, and her devoted people will shout with joy" — the divine speech answers v9\'s prayer: there the congregation prayed for priests clothed with righteousness and faithful people shouting; here YHWH promises priests clothed with <em>yēšaʿ</em> (salvation, deliverance). The exchange: human petition (v9) → divine promise (v16). <em>yēšaʿ</em> (salvation) in place of v9\'s <em>ṣedeq</em> (righteousness) — salvation as the fulfillment of righteousness.</p>',
    "17": '<p><strong>šām ʾaṣmîaḥ qeren lĕdāwid ʿāraktî nēr limsîḥî</strong> — "there I will make a shoot of strength grow for David; I have set a lamp ready for my anointed" — <em>ʾaṣmîaḥ qeren</em> (I will cause a horn to sprout/grow, Hiphil of <em>ṣāmaḥ</em>) — the pairing of <em>qeren</em> (horn = strength, power, dynasty) with <em>ṣāmaḥ</em> (to sprout, shoot up — agricultural growth verb) produces the "sprouting horn," a unique image. <em>ṣemaḥ</em> (a branch, shoot) will become the technical term for the Messiah in Jer 23:5, 33:15; Zech 3:8, 6:12 — the Branch. <em>nēr limsîḥî</em> (a lamp for my anointed) — the lamp burning in the dynasty; cf. 1 Kgs 11:36 ("that my servant David may always have a lamp before me in Jerusalem"). Luke 1:69 ("a horn of salvation in the house of his servant David") and 2:32 ("a light for revelation to the Gentiles") echo these images.</p>',
    "18": '<p><strong>ʾôyĕbāyw ʾalbîš bōšet wĕʿālāyw yāṣîṣ nizrô</strong> — "I will clothe his enemies in shame, but his crown will gleam/blossom upon his head" — the contrast of garments: enemies clothed in <em>bōšet</em> (shame, disgrace) :: the anointed wearing a gleaming crown. <em>yāṣîṣ nizrô</em> (his crown/diadem will gleam/blossom, from <em>ṣîṣ</em>, to shine, glisten, blossom) — the <em>nēzer</em> (crown, diadem, consecration, from <em>nāzar</em>, to consecrate/separate) is the priestly-royal crown. The verb <em>ṣîṣ</em> captures both shining (like polished gold) and blossoming (like a flower) — the Messianic promise closes Ps 132 with an image of radiant, flourishing kingship that will not fade.</p>',
  },
  "133": {
    "1": '<p><strong>hinnēh mah-ṭôb ûmah-nāʿîm šebet ʾaḥîm gam-yaḥad</strong> — "how good and how pleasant it is when brothers dwell together as one!" — <em>hinnēh</em> (behold, look!) — the exclamation points toward a visible reality. <em>mah-ṭôb</em> and <em>mah-nāʿîm</em> (how good! how pleasant!) — two different qualities of goodness: <em>ṭôb</em> (the basic goodness of creation, Gen 1:31) and <em>nāʿîm</em> (pleasantness, delight, aesthetic loveliness — the same root as Naomi). <em>šebet ʾaḥîm gam-yaḥad</em> (the sitting/dwelling of brothers also together) — <em>gam-yaḥad</em> (even/also together) — the <em>gam</em> (even, also) adds emphasis: brothers who are also one, not merely associated. The setting is the pilgrimage festival — the tribes assembled at Zion are "brothers" in the literal sense (one people) and in the symbolic sense (co-worshippers).</p>',
    "2": '<p><strong>kaššemen haṭṭôb ʿal-hārōʾš yōrēd ʿal-hazzāqān zĕqan-ʾahărōn šeyōrēd ʿal-pî middôtāyw</strong> — "it is like costly anointing oil poured on the head, running down over Aaron\'s beard — flowing down to the edge of his robes" — <em>šemen haṭṭôb</em> (the good/precious oil) — the consecration oil of Exod 30:22-25 (myrrh, cinnamon, cane, cassia in olive oil) used at Aaron\'s anointing (Lev 8:12). The oil flows from the head down — unity flows from the top of the community downward, anointing the whole. <em>pî middôtāyw</em> (lit. "the mouth/opening of his garments" = the collar/hem of his robes) — the oil reaches to the very edge of the priestly garment. The anointing that consecrates the High Priest covers him completely — so unity covers the whole community.</p>',
    "3": '<p><strong>kĕṭal-ḥermôn šeyyōrēd ʿal-harrê ṣiyyôn kî šām ṣiwwāh yhwh ʾet-habbĕrākāh ḥayyîm ʿad-hāʿôlām</strong> — "it is like the dew of Hermon descending on the mountains of Zion — for there the LORD has commanded the blessing: life that lasts forever" — <em>ṭal-ḥermôn</em> (dew of Hermon) — Mount Hermon (~2,814m) in the far north collects enormous quantities of moisture; its dew was proverbial for abundance and refreshment. Geographically, Hermon\'s dew cannot literally fall on Zion (300km south) — the simile is about the quality and abundance of refreshment, not geographic precision. <em>kî šām ṣiwwāh yhwh ʾet-habbĕrākāh</em> — "for there (<em>šām</em>, emphatic) YHWH commanded the blessing" — the place of unity is where divine blessing is decreed. <em>ḥayyîm ʿad-hāʿôlām</em> (life unto the age/forever) — the blessing is life itself, permanent life. The Songs of Ascents culminate in this vision: the pilgrims gathered at Zion in unity receive the blessing of life that endures.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 120-133 mkt-original written.')

if __name__ == '__main__':
    main()
